using System;
using System.Diagnostics;
using System.IO;
using System.Windows.Forms;

class Program {
    static string PS1_B64 = "";

    [STAThread]
    static void Main() {
        byte[] bytes;
        try {
            bytes = Convert.FromBase64String(PS1_B64);
        } catch (Exception ex) {
            MessageBox.Show("Erreur de decodage du script : " + ex.Message, "Installer EMS", MessageBoxButtons.OK, MessageBoxIcon.Error);
            return;
        }
        string tmp = Path.Combine(Path.GetTempPath(), "ems-install-" + Guid.NewGuid().ToString("N") + ".ps1");
        File.WriteAllBytes(tmp, bytes);
        try {
            var psi = new ProcessStartInfo {
                FileName = "powershell.exe",
                Arguments = string.Format("-ExecutionPolicy Bypass -WindowStyle Normal -File \"{0}\"", tmp),
                Verb = "runas",
                UseShellExecute = true
            };
            var p = Process.Start(psi);
            if (p != null) p.WaitForExit();
        } catch (Exception ex) {
            MessageBox.Show("Impossible de lancer le script : " + ex.Message + "\n\nAssurez-vous d'accepter la demande d'elevation (UAC).", "Installer EMS", MessageBoxButtons.OK, MessageBoxIcon.Warning);
        } finally {
            try { File.Delete(tmp); } catch {}
        }
    }
}
